https://alive2.llvm.org/ce/z/jf8swi
```llvm
define i1 @src(i8 %x) {
  %lshr = lshr i8 4, %x
  %trunc = trunc i8 %lshr to i1
  ret i1 %trunc
}

define i1 @tgt(i8 %x) {
  %cmp = icmp eq i8 %x, 2
  ret i1 %cmp
}
